<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --load</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> networkidle</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
